&lt;p&gt;&lt;span data-contrast=&quot;auto&quot;&gt;For more information, visit&amp;nbsp;&lt;/span&gt;&lt;a href=&quot;http://www.point72.com/working-here&quot;&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-charstyle=&quot;Hyperlink&quot;&gt;www.Point72.com/working-here&lt;/span&gt;&lt;/span&gt;&lt;/a&gt;&lt;span data-ccp-props=&quot;{&amp;quot;134233117&amp;quot;:false,&amp;quot;134233118&amp;quot;:false,&amp;quot;201341983&amp;quot;:0,&amp;quot;335559738&amp;quot;:0,&amp;quot;335559739&amp;quot;:160,&amp;quot;335559740&amp;quot;:276}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
